    const handleOutpaintingGenerate = useCallback(async (prompt: string) => {
        if (!outpaintingState) return;
        const genAI = getAi();
        if (!genAI) return;
        setIsGenerating(true);
        const { element, frame } = outpaintingState;
        try {
            const taskCanvas = document.createElement('canvas');
            taskCanvas.width = Math.ceil(frame.width);
            taskCanvas.height = Math.ceil(frame.height);
            const ctx = taskCanvas.getContext('2d');
            if (!ctx) throw new Error('Could not create canvas context');
            const originalImage = new Image();
            originalImage.src = element.src;
            await new Promise<void>((resolve, reject) => {
                originalImage.onload = () => resolve();
                originalImage.onerror = reject;
            });
            const drawX = (frame.width / 2) + (element.position.x - frame.position.x) - (element.width / 2);
            const drawY = (frame.height / 2) + (element.position.y - frame.position.y) - (element.height / 2);
            ctx.drawImage(originalImage, drawX, drawY, element.width, element.height);
            const taskImageB64 = taskCanvas.toDataURL('image/png');
            const [header, data] = taskImageB64.split(',');
            const mimeType = header.match(/data:(.*);base64/)?.[1] || 'image/png';
            const imagePart = { inlineData: { data, mimeType } };
            const finalPrompt = `This is an outpainting task. The existing image is part of a larger scene. Fill the surrounding transparent areas to naturally and seamlessly extend the image. User guidance: "${prompt || 'Continue the scene naturally.'}"`;
            const textPart = { text: finalPrompt };
            const response = await genAI.models.generateContent({
                model: 'gemini-2.5-flash-image',
                contents: { parts: [imagePart, textPart] },
                config: { responseModalities: [Modality.IMAGE, Modality.TEXT] },
            });
            const part = response.candidates[0].content.parts.find(p => p.inlineData);
            if (!part?.inlineData) throw new Error("AI did not return an image.");
            const newImageSrc = `data:image/png;base64,${part.inlineData.data}`;
            const updatedElement: ImageElement = { ...element, src: newImageSrc, position: { ...frame.position }, width: frame.width, height: frame.height };
            setElements(prev => prev.map(el => el.id === element.id ? updatedElement : el));
        } catch (error) {
            console.error("Error during outpainting:", error);
            alert("Failed to expand the image.");
        } finally {
            setIsGenerating(false);
            setOutpaintingState(null);
        }
    }, [outpaintingState, getAi, setElements]);

    const handleAutoPromptGenerate = useCallback(async (state: OutpaintingState): Promise<string> => {
        const genAI = getAi();
        if (!genAI) throw new Error("AI not initialized.");
        const { element, frame } = state;
        const taskCanvas = document.createElement('canvas');
        taskCanvas.width = Math.ceil(frame.width);
        taskCanvas.height = Math.ceil(frame.height);
        const ctx = taskCanvas.getContext('2d');
        if (!ctx) throw new Error('Could not create canvas context');
        const originalImage = new Image();
        originalImage.src = element.src;
        await new Promise<void>((resolve, reject) => {
            originalImage.onload = () => resolve();
            originalImage.onerror = reject;
        });
        const drawX = (frame.width / 2) + (element.position.x - frame.position.x) - (element.width / 2);
        const drawY = (frame.height / 2) + (element.position.y - frame.position.y) - (element.height / 2);
        ctx.drawImage(originalImage, drawX, drawY, element.width, element.height);
        const taskImageB64 = taskCanvas.toDataURL('image/png');
        const [header, data] = taskImageB64.split(',');
        const mimeType = header.match(/data:(.*);base64/)?.[1] || 'image/png';
        const imagePart = { inlineData: { data, mimeType } };
        const analysisPrompt = "Analyze the provided image and generate a concise, direct prompt to fill the transparent area for an expansion task. Prompt should be short instruction.";
        const textPart = { text: analysisPrompt };
        const response = await genAI.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: { parts: [imagePart, textPart] },
        });
        return response.text.trim();
    }, [getAi]);


  const addArrow = useCallback((position?: Point) => {
    const start = position || getTargetPosition();
    const end = { x: start.x + 150, y: start.y };
    const dx = end.x - start.x;
    const dy = end.y - start.y;
    const width = Math.sqrt(dx * dx + dy * dy);
    const rotation = Math.atan2(dy, dx) * (180 / Math.PI);
    const centerPosition = { x: (start.x + end.x) / 2, y: (start.y + end.y) / 2 };
    addElement({
      type: 'arrow',
      start,
      end,
      position: centerPosition,
      width,
      height: 30,
      rotation,
      color: 'text-red-500',
    });
  }, [addElement, getTargetPosition]);

  const triggerImageUpload = (position?: Point) => {
    lastImagePosition.current = position || null;
    imageInputRef.current?.click();
  };

  const addImagesToCanvas = useCallback((files: File[], basePosition: Point) => {
    const imagePromises = files.map((file, index) => {
      return new Promise<Omit<ImageElement, 'id' | 'zIndex'> | null>((resolve) => {
        const reader = new FileReader();
        reader.onload = (e) => {
          const src = e.target?.result as string;
          if (!src) return resolve(null);
          const img = new Image();
          img.onload = () => {
            const MAX_DIMENSION = 300;
            let { width, height } = img;
            if (width > MAX_DIMENSION || height > MAX_DIMENSION) {
              if (width > height) {
                height = (height / width) * MAX_DIMENSION;
                width = MAX_DIMENSION;
              } else {
                width = (width / height) * MAX_DIMENSION;
                height = MAX_DIMENSION;
              }
            }
            const position = { x: basePosition.x + index * 20, y: basePosition.y + index * 20 };
            resolve({ type: 'image', position, src, width, height, rotation: 0 });
          };
          img.onerror = () => resolve(null);
          img.src = src;
        };
        reader.onerror = () => resolve(null);
        reader.readAsDataURL(file);
      });
    });
    Promise.all(imagePromises).then(results => {
      const newElements = results.filter((el): el is Omit<ImageElement, 'id' | 'zIndex'> => el !== null);
      if (newElements.length > 0) {
        setElements(prev => [
          ...prev,
          ...newElements.map(el => ({
            ...el,
            id: `${Date.now()}-${Math.random().toString(36).substring(2, 9)}`,
            zIndex: zIndexCounter.current++,
          } as CanvasElement))
        ]);
      }
    });
  }, [setElements]);

  const handleImageUpload = useCallback((event: React.ChangeEvent<HTMLInputElement>) => {
    const files = event.target.files;
    if (!files || files.length === 0) return;
    const position = lastImagePosition.current || getTargetPosition();
    addImagesToCanvas(Array.from(files), position);
    lastImagePosition.current = null;
    if (imageInputRef.current) imageInputRef.current.value = "";
  }, [addImagesToCanvas, getTargetPosition]);

  const handleGenerate = useCallback(async (selectedElements: CanvasElement[]) => {
    const genAI = getAi();
    if (!genAI) return;
    const imageElements = selectedElements.filter(el => el.type === 'image' || el.type === 'drawing') as (ImageElement | DrawingElement)[];
    const noteElements = selectedElements.filter(el => el.type === 'note') as NoteElement[];
    if (imageElements.length === 0 && noteElements.length === 0) {
        alert("Select elements for context.");
        return;
    }
    setIsGenerating(true);
    setGeneratedImages(null);
    try {
      const instructions = noteElements.map(note => note.content).join(' \n');
      let finalInstructions = instructions;
      if (imageStyle && imageStyle !== 'Default') finalInstructions = instructions ? `${instructions}, ${imageStyle} Style` : `${imageStyle} Style`;
      let parts: any[];
      if (imageElements.length > 0) {
          const imageParts = imageElements.filter(el => el.src).map(el => {
              const [header, data] = el.src.split(',');
              const mimeType = header.match(/data:(.*);base64/)?.[1] || 'image/png';
              return { inlineData: { data, mimeType } };
          });
          parts = [...imageParts, { text: finalInstructions || "Reimagine the image(s)." }];
      } else {
          parts = [{ text: `Generate image based on description: "${finalInstructions}"` }];
      }
      const generateSingleImage = async () => {
        const response = await genAI.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: { parts },
            config: { responseModalities: [Modality.IMAGE, Modality.TEXT], imageConfig: { aspectRatio: imageAspectRatio } },
        });
        const part = response.candidates[0].content.parts.find(p => p.inlineData);
        return part ? `data:image/png;base64,${part.inlineData.data}` : null;
      };
      const [image1, image2] = await Promise.all([generateSingleImage(), generateSingleImage()]);
      setGeneratedImages([image1, image2].filter((img): img is string => img !== null));
    } catch (error) {
      console.error(error);
      alert("Generation failed.");
    } finally {
      setIsGenerating(false);
    }
  }, [getAi, imageStyle, imageAspectRatio]);

  const handleSelectElement = useCallback((id: string | null, shiftKey: boolean) => {
    if (contextMenu) setContextMenu(null);
    if (id === null) {
      if (!shiftKey) setSelectedElementIds([]);
      return;
    }
    const clickedElement = elements.find(el => el.id === id);
    if (clickedElement?.groupId && !shiftKey) {
        setSelectedElementIds(elements.filter(el => el.groupId === clickedElement.groupId).map(el => el.id));
        return;
    }
    setSelectedElementIds(prevIds => {
      if (shiftKey) return prevIds.includes(id) ? prevIds.filter(prevId => prevId !== id) : [...prevIds, id];
      return prevIds.includes(id) ? prevIds : [id];
    });
  }, [contextMenu, elements]);

  const handleMarqueeSelect = useCallback((ids: string[], shiftKey: boolean) => {
    setSelectedElementIds(prevIds => shiftKey ? [...new Set([...prevIds, ...ids])] : ids);
  }, []);

  const updateElements = useCallback((updatedElement: CanvasElement, dragDelta?: Point) => {
    setElements(prevElements => {
      const snap = (v: number) => snapToGrid ? Math.round(v / GRID_SIZE) * GRID_SIZE : v;
      if (dragDelta && selectedElementIds.length > 1 && selectedElementIds.includes(updatedElement.id)) {
        const selectedSet = new Set(selectedElementIds);
        return prevElements.map(el => {
          if (el.id === updatedElement.id) return { ...updatedElement, position: { x: snap(updatedElement.position.x), y: snap(updatedElement.position.y) } };
          if (selectedSet.has(el.id)) return { ...el, position: { x: snap(el.position.x + dragDelta.x), y: snap(el.position.y + dragDelta.y) } };
          return el;
        });
      }
      return prevElements.map(el => el.id === updatedElement.id ? { ...updatedElement, position: { x: snap(updatedElement.position.x), y: snap(updatedElement.position.y) } } : el);
    }, { addToHistory: false });
  }, [selectedElementIds, setElements, snapToGrid]);

  const updateMultipleElements = useCallback((updates: (Partial<CanvasElement> & { id: string })[], addToHistory: boolean = false) => {
      const updatesMap = new Map(updates.map(u => [u.id, u]));
      setElements(prev => prev.map(el => updatesMap.has(el.id) ? { ...el, ...updatesMap.get(el.id) } : el), { addToHistory });
  }, [setElements]);

  const handleInteractionEnd = useCallback(() => {
    setElements(currentElements => currentElements, { addToHistory: true });
  }, [setElements]);

  const deleteElement = useCallback(() => {
    if (selectedElementIds.length === 0) return;
    const selectedSet = new Set(selectedElementIds);
    setElements(prev => prev.filter(el => !selectedSet.has(el.id)));
    setSelectedElementIds([]);
  }, [selectedElementIds, setElements]);

  const groupElements = useCallback(() => {
    const newGroupId = `group-${Date.now()}`;
    const selectedSet = new Set(selectedElementIds);
    setElements(prev => prev.map(el => selectedSet.has(el.id) ? { ...el, groupId: newGroupId } : el));
  }, [selectedElementIds, setElements]);

  const ungroupElements = useCallback(() => {
    const selected = elements.filter(el => selectedElementIds.includes(el.id));
    const groupIdToUngroup = selected[0]?.groupId;
    if (!groupIdToUngroup) return;
    setElements(prev => prev.map(el => el.groupId === groupIdToUngroup ? { ...el, groupId: undefined } : el));
  }, [elements, selectedElementIds, setElements]);

  // --- Alignment Logic ---
  const alignSelected = useCallback((type: 'left' | 'center' | 'right' | 'top' | 'middle' | 'bottom') => {
    const selected = elements.filter(el => selectedElementIds.includes(el.id));
    if (selected.length <= 1) return;

    // Calculate selection boundary
    const bounds = {
      minX: Math.min(...selected.map(el => el.position.x - el.width / 2)),
      maxX: Math.max(...selected.map(el => el.position.x + el.width / 2)),
      minY: Math.min(...selected.map(el => el.position.y - el.height / 2)),
      maxY: Math.max(...selected.map(el => el.position.y + el.height / 2)),
    };

    const updates = selected.map(el => {
      const newPos = { ...el.position };
      if (type === 'left') newPos.x = bounds.minX + el.width / 2;
      if (type === 'center') newPos.x = (bounds.minX + bounds.maxX) / 2;
      if (type === 'right') newPos.x = bounds.maxX - el.width / 2;
      if (type === 'top') newPos.y = bounds.minY + el.height / 2;
      if (type === 'middle') newPos.y = (bounds.minY + bounds.maxY) / 2;
      if (type === 'bottom') newPos.y = bounds.maxY - el.height / 2;
      return { id: el.id, position: newPos };
    });

    updateMultipleElements(updates, true);
  }, [elements, selectedElementIds, updateMultipleElements]);

  // --- Distribution Logic ---
  const distributeSelected = useCallback((type: 'horizontal' | 'vertical') => {
    const selected = [...elements.filter(el => selectedElementIds.includes(el.id))];
    if (selected.length <= 2) return;

    if (type === 'horizontal') {
      selected.sort((a, b) => a.position.x - b.position.x);
      const minX = Math.min(...selected.map(el => el.position.x - el.width / 2));
      const maxX = Math.max(...selected.map(el => el.position.x + el.width / 2));
      const totalWidthOfItems = selected.reduce((sum, el) => sum + el.width, 0);
      const gap = (selected.length > 1) ? (maxX - minX - totalWidthOfItems) / (selected.length - 1) : 0;

      let currentX = minX;
      const updates = selected.map(el => {
        const newX = currentX + el.width / 2;
        currentX += el.width + gap;
        return { id: el.id, position: { ...el.position, x: newX } };
      });
      updateMultipleElements(updates, true);
    } else {
      selected.sort((a, b) => a.position.y - b.position.y);
      const minY = Math.min(...selected.map(el => el.position.y - el.height / 2));
      const maxY = Math.max(...selected.map(el => el.position.y + el.height / 2));
      const totalHeightOfItems = selected.reduce((sum, el) => sum + el.height, 0);
      const gap = (selected.length > 1) ? (maxY - minY - totalHeightOfItems) / (selected.length - 1) : 0;

      let currentY = minY;
      const updates = selected.map(el => {
        const newY = currentY + el.height / 2;
        currentY += el.height + gap;
        return { id: el.id, position: { ...el.position, y: newY } };
      });
      updateMultipleElements(updates, true);
    }
  }, [elements, selectedElementIds, updateMultipleElements]);

  // --- Auto Tidy Up Logic ---
  const tidyUpSelected = useCallback(() => {
    const selected = [...elements.filter(el => selectedElementIds.includes(el.id))];
    if (selected.length <= 1) return;

    // Sorting: Primary Y (with 50px tolerance for rows), secondary X
    selected.sort((a, b) => {
        const yDiff = a.position.y - b.position.y;
        if (Math.abs(yDiff) > 50) return yDiff;
        return a.position.x - b.position.x;
    });

    const cols = Math.ceil(Math.sqrt(selected.length));
    const padding = 50;
    const cellW = Math.max(...selected.map(el => el.width), 150);
    const cellH = Math.max(...selected.map(el => el.height), 120);

    const startX = Math.min(...selected.map(el => el.position.x - el.width / 2));
    const startY = Math.min(...selected.map(el => el.position.y - el.height / 2));

    const updates = selected.map((el, i) => {
        const row = Math.floor(i / cols);
        const col = i % cols;
        return {
            id: el.id,
            position: {
                x: startX + col * (cellW + padding) + el.width / 2,
                y: startY + row * (cellH + padding) + el.height / 2
            }
        };
    });

    updateMultipleElements(updates, true);
  }, [elements, selectedElementIds, updateMultipleElements]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (editingDrawing || editingImage || outpaintingState) return;
      const isMac = navigator.platform.toUpperCase().indexOf('MAC') >= 0;
      const isCtrlOrCmd = isMac ? e.metaKey : e.ctrlKey;
      if ((e.key === 'Delete' || e.key === 'Backspace') && !(e.target as HTMLElement).isContentEditable) {
        e.preventDefault(); deleteElement();
      }
      if (isCtrlOrCmd) {
        if (e.key.toLowerCase() === 'z') { e.preventDefault(); e.shiftKey ? redo() : undo(); }
        else if (e.key.toLowerCase() === 'y') { e.preventDefault(); redo(); }
        else if (e.key.toLowerCase() === 'g') { e.preventDefault(); e.shiftKey ? ungroupElements() : groupElements(); }
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [deleteElement, undo, redo, editingDrawing, editingImage, outpaintingState, groupElements, ungroupElements]);

  const bringToFront = useCallback(() => {
    const maxZ = Math.max(...elements.map(el => el.zIndex), 0);
    setElements(prev => prev.map(el => selectedElementIds.includes(el.id) ? { ...el, zIndex: maxZ + 1 } : el));
  }, [selectedElementIds, elements, setElements]);

  const sendToBack = useCallback(() => {
    const minZ = Math.min(...elements.map(el => el.zIndex), 0);
    setElements(prev => prev.map(el => selectedElementIds.includes(el.id) ? { ...el, zIndex: minZ - 1 } : el));
  }, [selectedElementIds, elements, setElements]);

  const handleImportCanvas = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (e) => {
        try {
            const data = JSON.parse(e.target?.result as string);
            setElements(Array.isArray(data) ? data : data.elements || []);
        } catch (error) { alert("Import failed."); }
    };
    reader.readAsText(file);
  };

  const selectedElements = elements.filter(el => selectedElementIds.includes(el.id));
  const t_key = (key: string) => t(key);

  return (
    <main className="relative w-screen h-screen bg-gray-100 font-sans" onClick={() => setContextMenu(null)}>
      {/* Sidebar Panel */}
      <div 
        className={`absolute top-4 z-20 p-4 bg-white/90 backdrop-blur-md rounded-xl shadow-2xl border border-gray-200 w-72 flex flex-col gap-4 transition-all duration-300 ease-in-out ${isMenuCollapsed ? (panelAlignment === 'left' ? '-translate-x-full' : 'translate-x-full') : 'translate-x-0'} ${panelAlignment === 'left' ? 'left-4' : 'right-4'}`}
      >
        <div className="flex justify-between items-start">
          <div>
            <h1 className="text-xl font-black text-blue-600 flex items-center gap-1">
                <span className="text-2xl">🍌</span> {t('infiniteCanvas')}
            </h1>
            <p className="text-[10px] text-blue-500 uppercase tracking-widest font-black">Ver 3.0.0.1 Flash <span className="text-gray-300">| Gemini 3</span></p>
          </div>
        </div>

        <div className="grid grid-cols-2 gap-2">
            <button onClick={() => addNote()} className="px-3 py-2.5 text-xs font-bold bg-blue-600 text-white rounded-lg hover:bg-blue-700 shadow-sm transition-all flex flex-col items-center gap-1">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/></svg>
                {t('addNote')}
            </button>
            <button onClick={() => addArrow()} className="px-3 py-2.5 text-xs font-bold bg-green-600 text-white rounded-lg hover:bg-green-700 shadow-sm transition-all flex flex-col items-center gap-1">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 8l4 4m0 0l-4 4m4-4H3"/></svg>
                {t('addArrow')}
            </button>
