                <button onClick={() => alignSelected('center')} title={t('alignCenter')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center transition-colors">
                  <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M12 2v20M6 6h12M8 12h8M6 18h12"/></svg>
                </button>
                <button onClick={() => alignSelected('right')} title={t('alignRight')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center transition-colors">
                  <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M20 2v20M4 6h12M8 12h8M4 18h10"/></svg>
                </button>
                <button onClick={() => alignSelected('top')} title={t('alignTop')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center transition-colors">
                  <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M2 4h20M6 8v12M12 8v8M18 8v10"/></svg>
                </button>
                <button onClick={() => alignSelected('middle')} title={t('alignMiddle')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center transition-colors">
                  <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M2 12h20M6 6h12M12 8h8M18 6h6"/></svg>
                </button>
                <button onClick={() => alignSelected('bottom')} title={t('alignBottom')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center transition-colors">
                  <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M2 20h20M6 4v12M12 4v8M18 4v10"/></svg>
                </button>
                <button onClick={() => distributeSelected('horizontal')} title={t('distributeHorizontally')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center transition-colors">
                  <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M4 2v20M20 2v20M10 6v12M14 6v12"/></svg>
                </button>
                <button onClick={() => distributeSelected('vertical')} title={t('distributeVertically')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center transition-colors">
                  <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M2 4h20M2 20h20M6 10h12M6 14h12"/></svg>
