  const updateElements = useCallback((updatedElement: CanvasElement, dragDelta?: Point) => {
    setElements(prevElements => {
      const snap = (v: number) => snapToGrid ? Math.round(v / GRID_SIZE) * GRID_SIZE : v;
      if (dragDelta && selectedElementIds.length > 1 && selectedElementIds.includes(updatedElement.id)) {
        const selectedSet = new Set(selectedElementIds);
        return prevElements.map(el => {
          if (el.id === updatedElement.id) return { ...updatedElement, position: { x: snap(updatedElement.position.x), y: snap(updatedElement.position.y) } };
          if (selectedSet.has(el.id)) return { ...el, position: { x: snap(el.position.x + dragDelta.x), y: snap(el.position.y + dragDelta.y) } };
          return el;
        });
      }
      return prevElements.map(el => el.id === updatedElement.id ? { ...updatedElement, position: { x: snap(updatedElement.position.x), y: snap(updatedElement.position.y) } } : el);
    }, { addToHistory: false });
  }, [selectedElementIds, setElements, snapToGrid]);

