  // --- Alignment Logic ---
  const alignSelected = useCallback((type: 'left' | 'center' | 'right' | 'top' | 'middle' | 'bottom') => {
    const selected = elements.filter(el => selectedElementIds.includes(el.id));
    if (selected.length <= 1) return;

    // Calculate selection boundary
    const bounds = {
      minX: Math.min(...selected.map(el => el.position.x - el.width / 2)),
      maxX: Math.max(...selected.map(el => el.position.x + el.width / 2)),
      minY: Math.min(...selected.map(el => el.position.y - el.height / 2)),
      maxY: Math.max(...selected.map(el => el.position.y + el.height / 2)),
    };

    const updates = selected.map(el => {
      const newPos = { ...el.position };
      if (type === 'left') newPos.x = bounds.minX + el.width / 2;
      if (type === 'center') newPos.x = (bounds.minX + bounds.maxX) / 2;
      if (type === 'right') newPos.x = bounds.maxX - el.width / 2;
      if (type === 'top') newPos.y = bounds.minY + el.height / 2;
      if (type === 'middle') newPos.y = (bounds.minY + bounds.maxY) / 2;
      if (type === 'bottom') newPos.y = bounds.maxY - el.height / 2;
      return { id: el.id, position: newPos };
    });

    updateMultipleElements(updates, true);
  }, [elements, selectedElementIds, updateMultipleElements]);

  // --- Distribution Logic ---
  const distributeSelected = useCallback((type: 'horizontal' | 'vertical') => {
    const selected = [...elements.filter(el => selectedElementIds.includes(el.id))];
    if (selected.length <= 2) return;

    if (type === 'horizontal') {
      selected.sort((a, b) => a.position.x - b.position.x);
      const minX = Math.min(...selected.map(el => el.position.x - el.width / 2));
      const maxX = Math.max(...selected.map(el => el.position.x + el.width / 2));
      const totalWidthOfItems = selected.reduce((sum, el) => sum + el.width, 0);
      const gap = (selected.length > 1) ? (maxX - minX - totalWidthOfItems) / (selected.length - 1) : 0;

      let currentX = minX;
      const updates = selected.map(el => {
        const newX = currentX + el.width / 2;
        currentX += el.width + gap;
        return { id: el.id, position: { ...el.position, x: newX } };
      });
      updateMultipleElements(updates, true);
    } else {
      selected.sort((a, b) => a.position.y - b.position.y);
      const minY = Math.min(...selected.map(el => el.position.y - el.height / 2));
      const maxY = Math.max(...selected.map(el => el.position.y + el.height / 2));
      const totalHeightOfItems = selected.reduce((sum, el) => sum + el.height, 0);
      const gap = (selected.length > 1) ? (maxY - minY - totalHeightOfItems) / (selected.length - 1) : 0;

      let currentY = minY;
      const updates = selected.map(el => {
        const newY = currentY + el.height / 2;
        currentY += el.height + gap;
        return { id: el.id, position: { ...el.position, y: newY } };
      });
      updateMultipleElements(updates, true);
    }
  }, [elements, selectedElementIds, updateMultipleElements]);

  // --- Auto Tidy Up Logic ---
  const tidyUpSelected = useCallback(() => {
    const selected = [...elements.filter(el => selectedElementIds.includes(el.id))];
    if (selected.length <= 1) return;

    // Sorting: Primary Y (with 50px tolerance for rows), secondary X
    selected.sort((a, b) => {
        const yDiff = a.position.y - b.position.y;
        if (Math.abs(yDiff) > 50) return yDiff;
        return a.position.x - b.position.x;
    });

    const cols = Math.ceil(Math.sqrt(selected.length));
    const padding = 50;
    const cellW = Math.max(...selected.map(el => el.width), 150);
    const cellH = Math.max(...selected.map(el => el.height), 120);

    const startX = Math.min(...selected.map(el => el.position.x - el.width / 2));
    const startY = Math.min(...selected.map(el => el.position.y - el.height / 2));

    const updates = selected.map((el, i) => {
        const row = Math.floor(i / cols);
        const col = i % cols;
        return {
            id: el.id,
            position: {
                x: startX + col * (cellW + padding) + el.width / 2,
                y: startY + row * (cellH + padding) + el.height / 2
            }
        };
    });

    updateMultipleElements(updates, true);
  }, [elements, selectedElementIds, updateMultipleElements]);

  // --- Analysis & Optimization Handlers ---
  /**
   * Analyzes an image or drawing element using Gemini 3 Pro model.
   * Provides a detailed description and improvement suggestions.
   */
  const handleAnalyzeElement = useCallback(async (elementId: string) => {
    const element = elements.find(el => el.id === elementId);
    if (!element || (element.type !== 'image' && element.type !== 'drawing') || !('src' in element) || !element.src) return;

    // Create new instance right before call as per guidelines
    const genAI = new GoogleGenAI({ apiKey: process.env.API_KEY });

    setAnalyzingElementId(elementId);
    try {
      const [header, data] = element.src.split(',');
      const mimeType = header.match(/data:(.*);base64/)?.[1] || 'image/png';

      const response = await genAI.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: [{
          parts: [
            { inlineData: { data, mimeType } },
            { text: "Analyze this image/drawing. Provide a detailed description and 3 creative suggestions for improvement or variation." }
          ]
        }],
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              description: { type: Type.STRING, description: "Detailed description of the content." },
              suggestions: { type: Type.ARRAY, items: { type: Type.STRING }, description: "3 suggestions for improvements." }
            },
            required: ["description", "suggestions"]
          }
        }
      });

      const result = JSON.parse(response.text);
      setAnalysisResults(prev => ({ ...prev, [elementId]: { en: result } }));
      setAnalysisVisibility(prev => ({ ...prev, [elementId]: true }));
    } catch (error) {
      console.error("Analysis failed:", error);
    } finally {
      setAnalyzingElementId(null);
    }
  }, [elements]);

  /**
   * Optimizes a note's text content for use as an image generation prompt.
   * Provides an optimized version and several creative variations.
   */
  const handleOptimizeNotePrompt = useCallback(async (elementId: string) => {
    const element = elements.find(el => el.id === elementId);
    if (!element || element.type !== 'note') return;

    const genAI = new GoogleGenAI({ apiKey: process.env.API_KEY });

    setAnalyzingElementId(elementId);
    try {
      const response = await genAI.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: `Optimize this text for an image generation prompt. Provide an optimized prompt and 3 creative variations: "${element.content}"`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              description: { type: Type.STRING, description: "The optimized image generation prompt." },
              suggestions: { type: Type.ARRAY, items: { type: Type.STRING }, description: "3 creative variations." }
            },
            required: ["description", "suggestions"]
          }
        }
      });

      const result = JSON.parse(response.text);
      setAnalysisResults(prev => ({ ...prev, [elementId]: { en: result } }));
      setAnalysisVisibility(prev => ({ ...prev, [elementId]: true }));
    } catch (error) {
      console.error("Optimization failed:", error);
    } finally {
      setAnalyzingElementId(null);
    }
  }, [elements]);

  /**
   * Translates an existing English analysis to Traditional Chinese using Gemini 3 Flash.
   */
  const handleTranslateAnalysis = useCallback(async (elementId: string) => {
    const analysis = analysisResults[elementId];
    if (!analysis || analysis.zh) return;

    const genAI = new GoogleGenAI({ apiKey: process.env.API_KEY });

    setTranslatingElementId(elementId);
    try {
      const contentToTranslate = JSON.stringify(analysis.en);
      const response = await genAI.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Translate this analysis JSON content into Traditional Chinese. Keep the JSON structure exactly the same: ${contentToTranslate}`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              description: { type: Type.STRING },
              suggestions: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["description", "suggestions"]
          }
        }
      });

      const result = JSON.parse(response.text);
      setAnalysisResults(prev => ({
        ...prev,
        [elementId]: { ...prev[elementId], zh: result }
      }));
    } catch (error) {
      console.error("Translation failed:", error);
    } finally {
      setTranslatingElementId(null);
    }
  }, [analysisResults]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (editingDrawing || editingImage || outpaintingState) return;
      const isMac = navigator.platform.toUpperCase().indexOf('MAC') >= 0;
      const isCtrlOrCmd = isMac ? e.metaKey : e.ctrlKey;
      if ((e.key === 'Delete' || e.key === 'Backspace') && !(e.target as HTMLElement).isContentEditable) {
        e.preventDefault(); deleteElement();
      }
      if (isCtrlOrCmd) {
        if (e.key.toLowerCase() === 'z') { e.preventDefault(); e.shiftKey ? redo() : undo(); }
        else if (e.key.toLowerCase() === 'y') { e.preventDefault(); redo(); }
        else if (e.key.toLowerCase() === 'g') { e.preventDefault(); e.shiftKey ? ungroupElements() : groupElements(); }
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [deleteElement, undo, redo, editingDrawing, editingImage, outpaintingState, groupElements, ungroupElements]);

  const bringToFront = useCallback(() => {
    const maxZ = Math.max(...elements.map(el => el.zIndex), 0);
    setElements(prev => prev.map(el => selectedElementIds.includes(el.id) ? { ...el, zIndex: maxZ + 1 } : el));
  }, [selectedElementIds, elements, setElements]);

  const sendToBack = useCallback(() => {
    const minZ = Math.min(...elements.map(el => el.zIndex), 0);
    setElements(prev => prev.map(el => selectedElementIds.includes(el.id) ? { ...el, zIndex: minZ - 1 } : el));
  }, [selectedElementIds, elements, setElements]);

  const handleImportCanvas = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (e) => {
        try {
            const data = JSON.parse(e.target?.result as string);
            setElements(Array.isArray(data) ? data : data.elements || []);
        } catch (error) { alert("Import failed."); }
    };
    reader.readAsText(file);
  };

  const selectedElements = elements.filter(el => selectedElementIds.includes(el.id));
  const t_key = (key: string) => t(key);

  return (
    <main className="relative w-screen h-screen bg-gray-100 font-sans" onClick={() => setContextMenu(null)}>
      {/* Sidebar Panel */}
      <div 
        className={`absolute top-4 z-20 p-4 bg-white/90 backdrop-blur-md rounded-xl shadow-2xl border border-gray-200 w-72 flex flex-col gap-4 transition-all duration-300 ease-in-out ${isMenuCollapsed ? (panelAlignment === 'left' ? '-translate-x-full' : 'translate-x-full') : 'translate-x-0'} ${panelAlignment === 'left' ? 'left-4' : 'right-4'}`}
      >
        <div className="flex justify-between items-start">
          <div>
            <h1 className="text-xl font-black text-blue-600 flex items-center gap-1">
                <span className="text-2xl">🍌</span> {t('infiniteCanvas')}
            </h1>
            <p className="text-[10px] text-blue-500 uppercase tracking-widest font-black">Ver 3.0.0.1 Flash <span className="text-gray-300">| Gemini 3</span></p>
          </div>
        </div>

        <div className="grid grid-cols-2 gap-2">
            <button onClick={() => addNote()} className="px-3 py-2.5 text-xs font-bold bg-blue-600 text-white rounded-lg hover:bg-blue-700 shadow-sm transition-all flex flex-col items-center gap-1">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/></svg>
                {t('addNote')}
            </button>
            <button onClick={() => addArrow()} className="px-3 py-2.5 text-xs font-bold bg-green-600 text-white rounded-lg hover:bg-green-700 shadow-sm transition-all flex flex-col items-center gap-1">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 8l4 4m0 0l-4 4m4-4H3"/></svg>
                {t('addArrow')}
            </button>
            <button onClick={() => addDrawing()} className="px-3 py-2.5 text-xs font-bold bg-purple-600 text-white rounded-lg hover:bg-purple-700 shadow-sm transition-all flex flex-col items-center gap-1 col-span-1">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z"/></svg>
                {t('addDrawing')}
            </button>
            <label className="cursor-pointer px-3 py-2.5 text-xs font-bold bg-orange-500 text-white rounded-lg hover:bg-orange-600 shadow-sm transition-all flex flex-col items-center gap-1 col-span-1">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"/></svg>
                {t('addImages')}
                <input type="file" accept="image/*" ref={imageInputRef} className="hidden" onChange={handleImageUpload} multiple />
            </label>
        </div>

        {/* Layout Tools Panel */}
        <div className="border-t border-gray-100 pt-3 flex flex-col gap-2">
            <h2 className="text-[10px] font-black text-gray-400 uppercase tracking-wider">{t('layout')}</h2>
            <div className="flex items-center gap-2 mb-1">
              <input 
                type="checkbox" 
                id="snapGrid" 
                checked={snapToGrid} 
                onChange={() => setSnapToGrid(!snapToGrid)}
                className="w-4 h-4 text-blue-600 rounded focus:ring-blue-500" 
              />
              <label htmlFor="snapGrid" className="text-xs font-bold text-gray-700 cursor-pointer">{t('snapToGrid')}</label>
            </div>
            {selectedElementIds.length > 1 ? (
              <div className="grid grid-cols-3 gap-1">
                <button onClick={() => alignSelected('left')} title={t('alignLeft')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center transition-colors">
                  <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M4 2v20M8 6h12M8 12h8M8 18h10"/></svg>
                </button>
                <button onClick={() => alignSelected('center')} title={t('alignCenter')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center transition-colors">
                  <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M12 2v20M6 6h12M8 12h8M6 18h12"/></svg>
                </button>
                <button onClick={() => alignSelected('right')} title={t('alignRight')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center transition-colors">
                  <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M20 2v20M4 6h12M8 12h8M4 18h10"/></svg>
                </button>
                <button onClick={() => alignSelected('top')} title={t('alignTop')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center transition-colors">
                  <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M2 4h20M6 8v12M12 8v8M18 8v10"/></svg>
                </button>
                <button onClick={() => alignSelected('middle')} title={t('alignMiddle')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center transition-colors">
                  <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M2 12h20M6 6h12M12 8h8M18 6h6"/></svg>
                </button>
                <button onClick={() => alignSelected('bottom')} title={t('alignBottom')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center transition-colors">
                  <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M2 20h20M6 4v12M12 4v8M18 4v10"/></svg>
                </button>
                <button onClick={() => distributeSelected('horizontal')} title={t('distributeHorizontally')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center transition-colors">
                  <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M4 2v20M20 2v20M10 6v12M14 6v12"/></svg>
                </button>
                <button onClick={() => distributeSelected('vertical')} title={t('distributeVertically')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center transition-colors">
                  <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M2 4h20M2 20h20M6 10h12M6 14h12"/></svg>
                </button>
                <button onClick={tidyUpSelected} title={t('tidyUp')} className="p-2 bg-indigo-100 hover:bg-indigo-200 text-indigo-700 rounded-md flex justify-center transition-colors">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16m-7 6h7"/></svg>
                </button>
              </div>
            ) : (
              <p className="text-[10px] text-gray-500 italic">{t('selectObjectToTransform')}</p>
            )}
        </div>

        {/* Existing color and control UI */}
        {selectedElementIds.length > 0 && selectedElements.some(el => el.type === 'note' || el.type === 'arrow') && (
            <div className="border-t border-gray-100 pt-3">
