interface ContextMenuData {
  x: number;
  y: number;
  worldPoint: Point;
  elementId: string | null;
}

export interface OutpaintingState {
  element: ImageElement;
  frame: {
    position: Point;
    width: number;
    height: number;
  };
}

const App: React.FC = () => {
  const { 
    state: elements, 
    setState: setElements, 
    undo, 
    redo, 
    canUndo, 
    canRedo 
  } = useHistoryState<CanvasElement[]>(INITIAL_ELEMENTS);

  const [selectedElementIds, setSelectedElementIds] = useState<string[]>([]);
  const [resetView, setResetView] = useState<() => void>(() => () => {});
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedImages, setGeneratedImages] = useState<string[] | null>(null);
  const [contextMenu, setContextMenu] = useState<ContextMenuData | null>(null);
  const [editingDrawing, setEditingDrawing] = useState<DrawingElement | null>(null);
  const [editingImage, setEditingImage] = useState<ImageElement | null>(null);
  const [outpaintingState, setOutpaintingState] = useState<OutpaintingState | null>(null);
  const [imageStyle, setImageStyle] = useState<string>('Default');
  const [imageAspectRatio, setImageAspectRatio] = useState<string>('1:1');
  const [isMenuCollapsed, setIsMenuCollapsed] = useState(false);
  const [isDraggingOver, setIsDraggingOver] = useState(false);
  const [language, setLanguage] = useState<'en' | 'zh'>('zh');
  const [panelAlignment, setPanelAlignment] = useState<'left' | 'right'>('left');
  const [interactionMode, setInteractionMode] = useState<'pan' | 'select'>('pan');
  const [analysisResults, setAnalysisResults] = useState<Record<string, AnalysisResult>>({});
  const [analyzingElementId, setAnalyzingElementId] = useState<string | null>(null);
  const [analysisVisibility, setAnalysisVisibility] = useState<Record<string, boolean>>({});
  const [translatingElementId, setTranslatingElementId] = useState<string | null>(null);
  const [snapToGrid, setSnapToGrid] = useState(true);
  const [viewport, setViewport] = useState<ViewportData>({
    x: 0,
    y: 0,
    width: window.innerWidth,
    height: window.innerHeight,
    zoom: 1
  });

  const imageInputRef = useRef<HTMLInputElement>(null);
  const importInputRef = useRef<HTMLInputElement>(null);
  const canvasApiRef = useRef<CanvasApi>(null);
  const lastImagePosition = useRef<Point | null>(null);
  const zIndexCounter = useRef(INITIAL_ELEMENTS.length);
  const dragCounter = useRef(0);
  const lastWorldMousePosition = useRef<Point | null>(null);

  const t = useCallback((key: string) => {
    return translations[language][key] || key;
  }, [language]);

  const toggleLanguage = useCallback(() => {
    setLanguage(prev => prev === 'en' ? 'zh' : 'en');
  }, []);

  const getAi = useCallback(() => {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
  }, []);

  const getCenterOfViewport = useCallback((): Point => {
    if (canvasApiRef.current) {
        const screenCenter: Point = {
            x: window.innerWidth / 2,
            y: window.innerHeight / 2,
        };
        return canvasApiRef.current.screenToWorld(screenCenter);
    }
    return {x: 0, y: 0};
  }, []);

  const getTargetPosition = useCallback((): Point => {
    const selected = elements.filter(el => selectedElementIds.includes(el.id));
    if (selected.length > 0) {
        const getRotatedCorners = (el: CanvasElement): Point[] => {
            const { x, y } = el.position;
            const { width, height, rotation } = el;
            const rad = rotation * (Math.PI / 180);
            const cos = Math.cos(rad);
            const sin = Math.sin(rad);
            const halfW = width / 2;
            const halfH = height / 2;
            const corners = [
                { x: -halfW, y: -halfH }, { x: halfW, y: -halfH },
                { x: halfW, y: halfH },   { x: -halfW, y: halfH }
            ];
            return corners.map(corner => ({
                x: x + corner.x * cos - corner.y * sin,
                y: y + corner.x * sin + corner.y * cos,
            }));
        };

        const allCorners = selected.flatMap(getRotatedCorners);
        const maxX = Math.max(...allCorners.map(c => c.x));
        const minY = Math.min(...allCorners.map(c => c.y));
        const maxY = Math.max(...allCorners.map(c => c.y));

        return { x: maxX + 250, y: (minY + maxY) / 2 };
    }

    if (lastWorldMousePosition.current) {
        return { x: lastWorldMousePosition.current.x + 20, y: lastWorldMousePosition.current.y + 20 };
    }

    return getCenterOfViewport();
  }, [elements, selectedElementIds, getCenterOfViewport]);

  const handleCanvasMouseMove = (worldPoint: Point) => {
    lastWorldMousePosition.current = worldPoint;
  };

  const handleViewportChange = useCallback((newViewport: ViewportData) => {
    setViewport(newViewport);
  }, []);

  const handleZoomIn = () => canvasApiRef.current?.zoomIn();
  const handleZoomOut = () => canvasApiRef.current?.zoomOut();
  const handlePanTo = (worldPoint: Point) => canvasApiRef.current?.panTo(worldPoint);

  const addElement = useCallback((newElement: Omit<NoteElement, 'id' | 'zIndex'> | Omit<ImageElement, 'id' | 'zIndex'> | Omit<ArrowElement, 'id' | 'zIndex'> | Omit<DrawingElement, 'id' | 'zIndex'>) => {
    const elementWithId: CanvasElement = {
        ...newElement,
        id: `${Date.now()}-${Math.random().toString(36).substring(2, 9)}`,
        zIndex: zIndexCounter.current++,
    } as CanvasElement;
     setElements(prev => [...prev, elementWithId]);
  }, [setElements]);

  const addNote = useCallback((position?: Point) => {
    addElement({
      type: 'note',
      position: position || getTargetPosition(),
      width: 150,
      height: 100,
      rotation: 0,
      content: 'New Note',
      color: COLORS[Math.floor(Math.random() * COLORS.length)].bg,
    });
  }, [addElement, getTargetPosition]);

  const addDrawing = useCallback((position?: Point) => {
    addElement({
      type: 'drawing',
      position: position || getTargetPosition(),
      width: 400,
      height: 300,
      rotation: 0,
      src: '',
    });
  }, [addElement, getTargetPosition]);

  const handleEditDrawing = useCallback((elementId: string) => {
      const element = elements.find(el => el.id === elementId);
      if (element && element.type === 'drawing') {
          setEditingDrawing(element);
      }
  }, [elements]);

  const handleSaveDrawing = (elementId: string, dataUrl: string) => {
      setElements(prev => prev.map(el =>
          el.id === elementId ? { ...el, src: dataUrl } : el
      ));
      setEditingDrawing(null);
  };

  const handleStartImageEdit = useCallback((elementId: string) => {
      const element = elements.find(el => el.id === elementId);
      if (element && element.type === 'image') {
          setEditingImage(element);
      }
  }, [elements]);

  const handleSaveImageEdit = (elementId: string, newSrc: string) => {
      setElements(prev => prev.map(el =>
          el.id === elementId && el.type === 'image' ? { ...el, src: newSrc } : el
      ));
      setEditingImage(null);
  };

  const handleStartOutpainting = useCallback((elementId: string) => {
      const element = elements.find(el => el.id === elementId && el.type === 'image') as ImageElement | undefined;
      if (element) {
          setOutpaintingState({
              element,
              frame: {
                  position: { ...element.position },
                  width: element.width,
                  height: element.height,
              }
          });
          setSelectedElementIds([]);
          setContextMenu(null);
      }
  }, [elements]);

  const handleUpdateOutpaintingFrame = useCallback((newFrame: { position: Point; width: number; height: number; }) => {
      setOutpaintingState(prev => prev ? { ...prev, frame: { ...prev.frame, ...newFrame } } : null);
  }, []);

  const handleCancelOutpainting = () => {
      setOutpaintingState(null);
  };

  const handleOutpaintingGenerate = useCallback(async (prompt: string) => {
      if (!outpaintingState) return;
      const genAI = getAi();
      setIsGenerating(true);
      const { element, frame } = outpaintingState;
      try {
          const taskCanvas = document.createElement('canvas');
          taskCanvas.width = Math.ceil(frame.width);
          taskCanvas.height = Math.ceil(frame.height);
          const ctx = taskCanvas.getContext('2d');
          if (!ctx) throw new Error('Could not create canvas context');
          const originalImage = new Image();
          originalImage.src = element.src;
          await new Promise<void>((resolve, reject) => {
              originalImage.onload = () => resolve();
              originalImage.onerror = reject;
          });
          const drawX = (frame.width / 2) + (element.position.x - frame.position.x) - (element.width / 2);
          const drawY = (frame.height / 2) + (element.position.y - frame.position.y) - (element.height / 2);
          ctx.drawImage(originalImage, drawX, drawY, element.width, element.height);
          const taskImageB64 = taskCanvas.toDataURL('image/png');
          const [header, data] = taskImageB64.split(',');
          const mimeType = header.match(/data:(.*);base64/)?.[1] || 'image/png';
          const response = await genAI.models.generateContent({
              model: 'gemini-2.5-flash-image',
              contents: { parts: [{ inlineData: { data, mimeType } }, { text: `Outpainting: ${prompt}` }] },
          });
          const part = response.candidates[0].content.parts.find(p => p.inlineData);
          if (!part?.inlineData) throw new Error("AI did not return an image.");
          const newImageSrc = `data:image/png;base64,${part.inlineData.data}`;
          setElements(prev => prev.map(el => el.id === element.id ? { ...element, src: newImageSrc, position: { ...frame.position }, width: frame.width, height: frame.height } : el));
      } catch (error) {
          console.error("Outpainting error:", error);
          alert("Failed to expand image.");
      } finally {
          setIsGenerating(false);
          setOutpaintingState(null);
      }
  }, [outpaintingState, getAi, setElements]);

  const handleAutoPromptGenerate = useCallback(async (state: OutpaintingState): Promise<string> => {
      const genAI = getAi();
      const response = await genAI.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: "Generate a short outpainting prompt for this scene.",
      });
      return response.text.trim();
  }, [getAi]);

  const addArrow = useCallback((position?: Point) => {
    const start = position || getTargetPosition();
    const end = { x: start.x + 150, y: start.y };
    const dx = end.x - start.x;
    const dy = end.y - start.y;
    const width = Math.sqrt(dx * dx + dy * dy);
    const rotation = Math.atan2(dy, dx) * (180 / Math.PI);
    addElement({
      type: 'arrow',
      start,
      end,
      position: { x: (start.x + end.x) / 2, y: (start.y + end.y) / 2 },
      width,
      height: 30,
      rotation,
      color: 'text-red-500',
    });
  }, [addElement, getTargetPosition]);

  const triggerImageUpload = (position?: Point) => {
    lastImagePosition.current = position || null;
    imageInputRef.current?.click();
  };

  const addImagesToCanvas = useCallback((files: File[], basePosition: Point) => {
    const imagePromises = files.map((file, index) => {
      return new Promise<Omit<ImageElement, 'id' | 'zIndex'> | null>((resolve) => {
        const reader = new FileReader();
        reader.onload = (e) => {
          const src = e.target?.result as string;
          if (!src) return resolve(null);
          const img = new Image();
          img.onload = () => {
            const MAX_DIMENSION = 300;
            let { width, height } = img;
            if (width > MAX_DIMENSION || height > MAX_DIMENSION) {
              if (width > height) { height = (height / width) * MAX_DIMENSION; width = MAX_DIMENSION; }
              else { width = (width / height) * MAX_DIMENSION; height = MAX_DIMENSION; }
            }
            resolve({ type: 'image', position: { x: basePosition.x + index * 20, y: basePosition.y + index * 20 }, src, width, height, rotation: 0 });
          };
          img.src = src;
        };
        reader.readAsDataURL(file);
      });
    });
    Promise.all(imagePromises).then(results => {
      const newElements = results.filter((el): el is Omit<ImageElement, 'id' | 'zIndex'> => el !== null);
      if (newElements.length > 0) {
        setElements(prev => [...prev, ...newElements.map(el => ({ ...el, id: `${Date.now()}-${Math.random().toString(36).substring(2, 9)}`, zIndex: zIndexCounter.current++ } as CanvasElement))]);
      }
    });
  }, [setElements]);

  const handleImageUpload = useCallback((event: React.ChangeEvent<HTMLInputElement>) => {
    const files = event.target.files;
    if (!files || files.length === 0) return;
    addImagesToCanvas(Array.from(files), lastImagePosition.current || getTargetPosition());
    lastImagePosition.current = null;
    if (imageInputRef.current) imageInputRef.current.value = "";
  }, [addImagesToCanvas, getTargetPosition]);

  const handleGenerate = useCallback(async (selectedElements: CanvasElement[]) => {
    const genAI = getAi();
    setIsGenerating(true);
    try {
      const response = await genAI.models.generateContent({
          model: 'gemini-2.5-flash-image',
          contents: "Generate image based on notes.",
          config: { responseModalities: [Modality.IMAGE, Modality.TEXT] as any, imageConfig: { aspectRatio: imageAspectRatio as any } },
      });
      const part = response.candidates[0].content.parts.find(p => p.inlineData);
      if (part?.inlineData) setGeneratedImages([`data:image/png;base64,${part.inlineData.data}`]);
    } catch (error) {
      console.error(error);
    } finally {
      setIsGenerating(false);
    }
  }, [getAi, imageStyle, imageAspectRatio]);

  const handleSelectElement = useCallback((id: string | null, shiftKey: boolean) => {
    if (contextMenu) setContextMenu(null);
    if (id === null) { if (!shiftKey) setSelectedElementIds([]); return; }
    const clickedElement = elements.find(el => el.id === id);
    if (clickedElement?.groupId && !shiftKey) {
        setSelectedElementIds(elements.filter(el => el.groupId === clickedElement.groupId).map(el => el.id));
        return;
    }
    setSelectedElementIds(prevIds => shiftKey ? (prevIds.includes(id) ? prevIds.filter(pid => pid !== id) : [...prevIds, id]) : [id]);
  }, [contextMenu, elements]);

  const handleMarqueeSelect = useCallback((ids: string[], shiftKey: boolean) => {
    setSelectedElementIds(prevIds => shiftKey ? [...new Set([...prevIds, ...ids])] : ids);
  }, []);

  const updateElements = useCallback((updatedElement: CanvasElement, dragDelta?: Point) => {
    setElements(prevElements => {
      const snap = (v: number) => snapToGrid ? Math.round(v / GRID_SIZE) * GRID_SIZE : v;
      if (dragDelta && selectedElementIds.length > 1 && selectedElementIds.includes(updatedElement.id)) {
        const selectedSet = new Set(selectedElementIds);
        return prevElements.map(el => {
          if (el.id === updatedElement.id) return { ...updatedElement, position: { x: snap(updatedElement.position.x), y: snap(updatedElement.position.y) } };
          if (selectedSet.has(el.id)) return { ...el, position: { x: snap(el.position.x + dragDelta.x), y: snap(el.position.y + dragDelta.y) } };
          return el;
        });
      }
      return prevElements.map(el => el.id === updatedElement.id ? { ...updatedElement, position: { x: snap(updatedElement.position.x), y: snap(updatedElement.position.y) } } : el);
    }, { addToHistory: false });
  }, [selectedElementIds, setElements, snapToGrid]);

  const updateMultipleElements = useCallback((updates: (Partial<CanvasElement> & { id: string })[], addToHistory: boolean = false) => {
      const updatesMap = new Map(updates.map(u => [u.id, u]));
      // FIX: Cast the merged object to CanvasElement to satisfy the union type requirement when performing partial updates.
      setElements(prev => prev.map(el => {
        const update = updatesMap.get(el.id);
        return update ? ({ ...el, ...update } as CanvasElement) : el;
      }), { addToHistory });
  }, [setElements]);

  const handleInteractionEnd = useCallback(() => {
    setElements(currentElements => currentElements, { addToHistory: true });
  }, [setElements]);

  const deleteElement = useCallback(() => {
    setElements(prev => prev.filter(el => !selectedElementIds.includes(el.id)));
    setSelectedElementIds([]);
  }, [selectedElementIds, setElements]);

  const getSelectedGroupInfo = useMemo(() => {
    const selected = elements.filter(el => selectedElementIds.includes(el.id));
    if (selected.length === 0) return { canGroup: false, canUngroup: false };
    const groupIds = new Set(selected.map(el => el.groupId).filter(Boolean));
    return { canGroup: selected.length > 1, canUngroup: groupIds.size > 0 };
  }, [elements, selectedElementIds]);

  const groupElements = useCallback(() => {
    const newGroupId = `group-${Date.now()}`;
    setElements(prev => prev.map(el => selectedElementIds.includes(el.id) ? { ...el, groupId: newGroupId } : el));
  }, [selectedElementIds, setElements]);

  const ungroupElements = useCallback(() => {
    setElements(prev => prev.map(el => selectedElementIds.includes(el.id) ? { ...el, groupId: undefined } : el));
  }, [selectedElementIds, setElements]);

  // --- 選取物件的對齊、均分、自動排版功能 ---

  const alignSelected = useCallback((type: 'left' | 'center' | 'right' | 'top' | 'middle' | 'bottom') => {
    const selected = elements.filter(el => selectedElementIds.includes(el.id));
    if (selected.length <= 1) return;

    // 計算選取範圍的整體邊界 (Bounding Box)
    const bounds = {
      minX: Math.min(...selected.map(el => el.position.x - el.width / 2)),
      maxX: Math.max(...selected.map(el => el.position.x + el.width / 2)),
      minY: Math.min(...selected.map(el => el.position.y - el.height / 2)),
      maxY: Math.max(...selected.map(el => el.position.y + el.height / 2)),
    };

    const updates = selected.map(el => {
      let newPos = { ...el.position };
      if (type === 'left') newPos.x = bounds.minX + el.width / 2;
      else if (type === 'center') newPos.x = (bounds.minX + bounds.maxX) / 2;
      else if (type === 'right') newPos.x = bounds.maxX - el.width / 2;
      else if (type === 'top') newPos.y = bounds.minY + el.height / 2;
      else if (type === 'middle') newPos.y = (bounds.minY + bounds.maxY) / 2;
      else if (type === 'bottom') newPos.y = bounds.maxY - el.height / 2;
      return { id: el.id, position: newPos };
    });

    updateMultipleElements(updates, true);
  }, [elements, selectedElementIds, updateMultipleElements]);

  const distributeSelected = useCallback((type: 'horizontal' | 'vertical') => {
    const selected = [...elements.filter(el => selectedElementIds.includes(el.id))];
    if (selected.length <= 2) return;

    if (type === 'horizontal') {
      selected.sort((a, b) => a.position.x - b.position.x);
      const minX = Math.min(...selected.map(el => el.position.x - el.width / 2));
      const maxX = Math.max(...selected.map(el => el.position.x + el.width / 2));
      const itemsWidthSum = selected.reduce((sum, el) => sum + el.width, 0);
      const gap = (maxX - minX - itemsWidthSum) / (selected.length - 1);

      let currentX = minX;
      const updates = selected.map(el => {
        const newX = currentX + el.width / 2;
        currentX += el.width + gap;
        return { id: el.id, position: { ...el.position, x: newX } };
      });
      updateMultipleElements(updates, true);
    } else {
      selected.sort((a, b) => a.position.y - b.position.y);
      const minY = Math.min(...selected.map(el => el.position.y - el.height / 2));
      const maxY = Math.max(...selected.map(el => el.position.y + el.height / 2));
      const itemsHeightSum = selected.reduce((sum, el) => sum + el.height, 0);
      const gap = (maxY - minY - itemsHeightSum) / (selected.length - 1);

      let currentY = minY;
      const updates = selected.map(el => {
        const newY = currentY + el.height / 2;
        currentY += el.height + gap;
        return { id: el.id, position: { ...el.position, y: newY } };
      });
      updateMultipleElements(updates, true);
    }
  }, [elements, selectedElementIds, updateMultipleElements]);

  const tidyUpSelected = useCallback(() => {
    const selected = [...elements.filter(el => selectedElementIds.includes(el.id))];
    if (selected.length <= 1) return;

    // 先根據 Y 軸排序 (容差 100px 視為同一行)，再根據 X 軸排序
    selected.sort((a, b) => {
        const yDiff = a.position.y - b.position.y;
        if (Math.abs(yDiff) > 100) return yDiff;
        return a.position.x - b.position.x;
    });

    const cols = Math.ceil(Math.sqrt(selected.length));
    const padding = 60;
    const cellW = Math.max(...selected.map(el => el.width)) + padding;
    const cellH = Math.max(...selected.map(el => el.height)) + padding;

    const startX = Math.min(...selected.map(el => el.position.x - el.width / 2)) + selected[0].width / 2;
    const startY = Math.min(...selected.map(el => el.position.y - el.height / 2)) + selected[0].height / 2;

    const updates = selected.map((el, i) => {
        const row = Math.floor(i / cols);
        const col = i % cols;
        return {
            id: el.id,
            position: {
                x: startX + col * cellW,
                y: startY + row * cellH
            }
        };
    });

    updateMultipleElements(updates, true);
  }, [elements, selectedElementIds, updateMultipleElements]);

  // --- 其他事件與渲染 ---

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      const isMac = navigator.platform.toUpperCase().indexOf('MAC') >= 0;
      const isCtrlOrCmd = isMac ? e.metaKey : e.ctrlKey;
      if (e.key === 'Delete' || e.key === 'Backspace') deleteElement();
      if (isCtrlOrCmd && e.key === 'z') e.shiftKey ? redo() : undo();
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [deleteElement, undo, redo]);

  const bringToFront = useCallback(() => {
    const maxZ = Math.max(...elements.map(el => el.zIndex), 0);
    setElements(prev => prev.map(el => selectedElementIds.includes(el.id) ? { ...el, zIndex: maxZ + 1 } : el));
  }, [selectedElementIds, elements, setElements]);

  const sendToBack = useCallback(() => {
    const minZ = Math.min(...elements.map(el => el.zIndex), 0);
    setElements(prev => prev.map(el => selectedElementIds.includes(el.id) ? { ...el, zIndex: minZ - 1 } : el));
  }, [selectedElementIds, elements, setElements]);

  const handleExportCanvas = () => {
    const blob = new Blob([JSON.stringify(elements, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a'); a.href = url; a.download = 'canvas.json'; a.click();
  };

  const handleImportCanvas = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]; if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => setElements(JSON.parse(event.target?.result as string));
    reader.readAsText(file);
  };

  const handleAnalyzeElement = useCallback(async (id: string) => {
      const genAI = getAi();
      setAnalyzingElementId(id);
      try {
          const response = await genAI.models.generateContent({ model: 'gemini-3-flash-preview', contents: "Analyze element content." });
          setAnalysisResults(prev => ({ ...prev, [id]: { en: { description: response.text || '', suggestions: [] } } }));
          setAnalysisVisibility(prev => ({ ...prev, [id]: true }));
      } finally { setAnalyzingElementId(null); }
  }, [getAi]);

  const handleOptimizeNotePrompt = useCallback(async (id: string) => {
      const genAI = getAi();
      setAnalyzingElementId(id);
      try {
          const response = await genAI.models.generateContent({ model: 'gemini-3-flash-preview', contents: "Optimize prompt." });
          setAnalysisResults(prev => ({ ...prev, [id]: { en: { description: response.text || '', suggestions: [] } } }));
          setAnalysisVisibility(prev => ({ ...prev, [id]: true }));
      } finally { setAnalyzingElementId(null); }
  }, [getAi]);

  const handleTranslateAnalysis = useCallback(async (id: string) => {
      const genAI = getAi();
      setTranslatingElementId(id);
      try {
          const response = await genAI.models.generateContent({ model: 'gemini-3-flash-preview', contents: "Translate to Chinese." });
          setAnalysisResults(prev => ({ ...prev, [id]: { ...prev[id], zh: { description: response.text || '', suggestions: [] } } }));
      } finally { setTranslatingElementId(null); }
  }, [getAi]);

  // FIX: Added handleContextMenu implementation to handle right-clicks and long-presses.
  const handleContextMenu = useCallback((e: React.MouseEvent | React.TouchEvent, worldPoint: Point, elementId: string | null) => {
    if ('preventDefault' in e) e.preventDefault();
    if ('stopPropagation' in e) e.stopPropagation();

    const point = 'touches' in e ? e.touches[0] : (e as React.MouseEvent);
    setContextMenu({
      x: point.clientX,
      y: point.clientY,
      worldPoint,
      elementId
    });
  }, []);

  return (
    <main className="relative w-screen h-screen bg-gray-100 font-sans" onClick={() => setContextMenu(null)}>
      <div className={`absolute top-4 z-20 p-4 bg-white/90 backdrop-blur-md rounded-xl shadow-2xl border border-gray-200 w-72 flex flex-col gap-4 transition-all duration-300 ease-in-out ${isMenuCollapsed ? (panelAlignment === 'left' ? '-translate-x-full' : 'translate-x-full') : 'translate-x-0'} ${panelAlignment === 'left' ? 'left-4' : 'right-4'}`}>
        <div className="flex justify-between items-start">
          <div>
            <h1 className="text-xl font-black text-blue-600 flex items-center gap-1"><span className="text-2xl">🍌</span> {t('infiniteCanvas')}</h1>
            <p className="text-[10px] text-blue-500 uppercase tracking-widest font-black">Ver 3.0.0.1 Flash <span className="text-gray-300">| Gemini 3</span></p>
          </div>
        </div>

        <div className="grid grid-cols-2 gap-2">
            <button onClick={() => addNote()} className="px-3 py-2.5 text-xs font-bold bg-blue-600 text-white rounded-lg hover:bg-blue-700 shadow-sm transition-all flex flex-col items-center gap-1"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/></svg>{t('addNote')}</button>
            <button onClick={() => addArrow()} className="px-3 py-2.5 text-xs font-bold bg-green-600 text-white rounded-lg hover:bg-green-700 shadow-sm transition-all flex flex-col items-center gap-1"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 8l4 4m0 0l-4 4m4-4H3"/></svg>{t('addArrow')}</button>
            <button onClick={() => addDrawing()} className="px-3 py-2.5 text-xs font-bold bg-purple-600 text-white rounded-lg hover:bg-purple-700 shadow-sm transition-all flex flex-col items-center gap-1"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z"/></svg>{t('addDrawing')}</button>
            <label className="cursor-pointer px-3 py-2.5 text-xs font-bold bg-orange-500 text-white rounded-lg hover:bg-orange-600 shadow-sm transition-all flex flex-col items-center gap-1"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"/></svg>{t('addImages')}<input type="file" accept="image/*" ref={imageInputRef} className="hidden" onChange={handleImageUpload} multiple /></label>
        </div>

        <div className="border-t border-gray-100 pt-3 flex flex-col gap-2">
            <h2 className="text-[10px] font-black text-gray-400 uppercase tracking-wider">{t('layout')}</h2>
            <div className="flex items-center gap-2 mb-1">
              <input type="checkbox" id="snapGrid" checked={snapToGrid} onChange={() => setSnapToGrid(!snapToGrid)} className="w-4 h-4 text-blue-600 rounded focus:ring-blue-500" />
              <label htmlFor="snapGrid" className="text-xs font-bold text-gray-700 cursor-pointer">{t('snapToGrid')}</label>
            </div>
            {selectedElementIds.length > 1 ? (
              <div className="grid grid-cols-3 gap-1">
                <button onClick={() => alignSelected('left')} title={t('alignLeft')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center"><svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M4 2v20M8 6h12M8 12h8M8 18h10"/></svg></button>
                <button onClick={() => alignSelected('center')} title={t('alignCenter')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center"><svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M12 2v20M6 6h12M8 12h8M6 18h12"/></svg></button>
                <button onClick={() => alignSelected('right')} title={t('alignRight')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center"><svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M20 2v20M4 6h12M8 12h8M4 18h10"/></svg></button>
                <button onClick={() => alignSelected('top')} title={t('alignTop')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center"><svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M2 4h20M6 8v12M12 8v8M18 8v10"/></svg></button>
                <button onClick={() => alignSelected('middle')} title={t('alignMiddle')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center"><svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M2 12h20M6 6h12M12 8h8M18 6h6"/></svg></button>
                <button onClick={() => alignSelected('bottom')} title={t('alignBottom')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center"><svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M2 20h20M6 4v12M12 4v8M18 4v10"/></svg></button>
                <button onClick={() => distributeSelected('horizontal')} title={t('distributeHorizontally')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center"><svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M4 2v20M20 2v20M10 6v12M14 6v12"/></svg></button>
                <button onClick={() => distributeSelected('vertical')} title={t('distributeVertically')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center"><svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M2 4h20M2 20h20M6 10h12M6 14h12"/></svg></button>
                <button onClick={tidyUpSelected} title={t('tidyUp')} className="p-2 bg-indigo-100 hover:bg-indigo-200 text-indigo-700 rounded-md flex justify-center"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16m-7 6h7"/></svg></button>
              </div>
            ) : <p className="text-[10px] text-gray-500 italic">{t('selectObjectToTransform')}</p>}
        </div>

        <div className="flex flex-col gap-2 border-t border-gray-100 pt-3">
            <h2 className="text-[10px] font-black text-gray-400 uppercase tracking-wider">{t('controls')}</h2>
            <div className="grid grid-cols-2 gap-2">
                <button onClick={undo} disabled={!canUndo} className="px-2 py-2 text-xs font-bold bg-gray-100 rounded-lg disabled:opacity-30">{t('undo')}</button>
                <button onClick={redo} disabled={!canRedo} className="px-2 py-2 text-xs font-bold bg-gray-100 rounded-lg disabled:opacity-30">{t('redo')}</button>
                <button onClick={deleteElement} className="px-2 py-2 text-xs font-bold bg-red-50 text-red-600 rounded-lg">{t('delete')}</button>
                <button onClick={resetView} className="px-2 py-2 text-xs font-bold bg-gray-200 rounded-lg">{t('resetView')}</button>
            </div>
        </div>
      </div>

      <InfiniteCanvas 
        ref={canvasApiRef}
        elements={elements} 
        selectedElementIds={selectedElementIds}
        onSelectElement={handleSelectElement}
        onMarqueeSelect={handleMarqueeSelect}
        onUpdateElement={updateElements}
        onUpdateMultipleElements={updateMultipleElements}
        onInteractionEnd={handleInteractionEnd}
        // FIX: Replaced getResetViewCallback with setResetView to correctly pass the callback registration function.
        setResetViewCallback={setResetView} 
        onGenerate={handleGenerate}
        onContextMenu={handleContextMenu}
        onEditDrawing={handleEditDrawing}
        onMouseMove={handleCanvasMouseMove}
        onViewportChange={handleViewportChange}
        imageStyle={imageStyle}
        onSetImageStyle={setImageStyle}
        imageAspectRatio={imageAspectRatio}
        onSetImageAspectRatio={setImageAspectRatio}
        outpaintingState={outpaintingState}
        onUpdateOutpaintingFrame={handleUpdateOutpaintingFrame}
        onCancelOutpainting={handleCancelOutpainting}
        onOutpaintingGenerate={handleOutpaintingGenerate}
        onAutoPromptGenerate={handleAutoPromptGenerate}
        interactionMode={interactionMode}
        t={t}
        language={language}
        analysisResults={analysisResults}
        analyzingElementId={analyzingElementId}
        onAnalyzeElement={handleAnalyzeElement}
        onOptimizeNotePrompt={handleOptimizeNotePrompt}
        analysisVisibility={analysisVisibility}
        onToggleAnalysisVisibility={id => setAnalysisVisibility(p => ({ ...p, [id]: !p[id] }))}
        onClearAnalysis={id => setAnalysisResults(p => { const n = { ...p }; delete n[id]; return n; })}
        onTranslateAnalysis={handleTranslateAnalysis}
        translatingElementId={translatingElementId}
      />
      <Minimap elements={elements} viewport={viewport} onPanTo={handlePanTo} onZoomIn={handleZoomIn} onZoomOut={handleZoomOut} />

      {/* FIX: Render the ContextMenu when state is active */}
      {contextMenu && (
        <ContextMenu
          menuData={contextMenu}
          onClose={() => setContextMenu(null)}
          actions={{
            addNote,
            addArrow,
            addDrawing,
            editDrawing: handleEditDrawing,
            startImageEdit: handleStartImageEdit,
            startOutpainting: handleStartOutpainting,
            addImage: triggerImageUpload,
            deleteElement,
            bringToFront,
            sendToBack,
            changeColor: (color) => updateMultipleElements(selectedElementIds.map(id => ({ id, color })), true),
            downloadImage: (id) => {
              const el = elements.find(e => e.id === id) as ImageElement | DrawingElement;
              if (el?.src) {
                const a = document.createElement('a'); a.href = el.src; a.download = 'canvas-item.png'; a.click();
              }
            },
            duplicateElement: (id) => {
                const el = elements.find(e => e.id === id);
                if (el) {
                  const newEl = { ...el, id: `${Date.now()}-${Math.random()}`, position: { x: el.position.x + 20, y: el.position.y + 20 }, zIndex: zIndexCounter.current++ };
                  setElements(prev => [...prev, newEl as CanvasElement]);
                }
            },
            toggleLanguage,
            groupElements,
            ungroupElements,
            copyToClipboard: (id) => {
              const el = elements.find(e => e.id === id);
              if (el && 'content' in el) navigator.clipboard.writeText(el.content);
              else if (el && 'src' in el && el.src) navigator.clipboard.writeText(el.src);
            }
          }}
          canChangeColor={selectedElementIds.length > 0 && elements.filter(el => selectedElementIds.includes(el.id)).every(el => el.type === 'note' || el.type === 'arrow')}
          canGroup={getSelectedGroupInfo.canGroup}
          canUngroup={getSelectedGroupInfo.canUngroup}
          elementType={contextMenu.elementId ? elements.find(el => el.id === contextMenu.elementId)?.type || null : null}
          t={t}
        />
      )}

      {/* FIX: Render modals for drawing and image editing functionality */}
      {editingDrawing && (
        <DrawingModal
          element={editingDrawing}
          onSave={handleSaveDrawing}
          onClose={() => setEditingDrawing(null)}
          t={t}
        />
      )}

      {editingImage && (
        <ImageEditModal
          element={editingImage}
          onSave={handleSaveImageEdit}
          onClose={() => setEditingImage(null)}
          ai={getAi()}
          t={t}
        />
      )}
    </main>
  );
};

export default App;
